#!/usr/bin/env python3
import urllib.request
import urllib.error
import sys
import ssl

def test_endpoint(url, name):
    try:
        print(f"Testing {name}: {url}")
        # Create a request with custom headers
        req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'})

        # For HTTPS URLs, create an unverified context to avoid SSL certificate issues
        if url.startswith('https:'):
            context = ssl._create_unverified_context()
            response = urllib.request.urlopen(req, context=context, timeout=10)
        else:
            response = urllib.request.urlopen(req, timeout=10)

        # Read the response
        content = response.read().decode('utf-8')
        print(f"Status Code: {response.getcode()}")
        print(f"Response: {content[:200]}..." if len(content) > 200 else f"Response: {content}")

        if response.getcode() >= 400:
            print(f"WARNING: {name} returned error status code {response.getcode()}\n")
            return response.getcode()
        else:
            print(f"SUCCESS: {name} is reachable\n")
            return response.getcode()

    except urllib.error.HTTPError as e:
        print(f"HTTP Error: {name} - {e.code} {e.reason}")
        print(f"Response: {e.read().decode('utf-8')}")
        print()
        return e.code
    except urllib.error.URLError as e:
        print(f"URL Error: Failed to connect to {name} - {e}\n")
        return None
    except Exception as e:
        print(f"Error: Failed to connect to {name} - {e}\n")
        return None

# Test the endpoints
status1 = test_endpoint('http://localhost:3003/checkConnectivity?variant=2', 'Local Service')
status2 = test_endpoint('https://httpstat.us/200', 'HTTPS Test')

# Exit with error if any test failed
if (status1 is not None and status1 >= 400) or status2 is None:
    sys.exit(1)
else:
    sys.exit(0)

#!/usr/bin/env python3
import urllib.request
import urllib.error
import json

def check_endpoint(url, name):
    try:
        response = urllib.request.urlopen(url, timeout=10)
        return {
            'name': name,
            'url': url,
            'status': 'UP',
            'http_code': response.getcode(),
            'error': None
        }
    except urllib.error.HTTPError as e:
        return {
            'name': name,
            'url': url,
            'status': 'DOWN',
            'http_code': e.code,
            'error': str(e)
        }
    except Exception as e:
        return {
            'name': name,
            'url': url,
            'status': 'DOWN',
            'http_code': None,
            'error': str(e)
        }

# Test the endpoints
endpoints = [
    ('http://localhost:3003/checkConnectivity?variant=2', 'Local Service'),
    ('https://httpstat.us/200', 'External Test Endpoint')
]

results = []
for url, name in endpoints:
    result = check_endpoint(url, name)
    results.append(result)
    print(f"{name} ({url}): {result['status']}")
    if result['error']:
        print(f"  Error: {result['error']}")
    if result['http_code']:
        print(f"  HTTP Code: {result['http_code']}")

const http = require('http');

const server = http.createServer((req, res) => {
  res.writeHead(200, { 'Content-Type': 'application/json' });
  res.end(JSON.stringify({ status: 'healthy', timestamp: new Date().toISOString() }));
});

const port = 3004;
server.listen(port, '127.0.0.1', () => {
  console.log(`Test server running at http://127.0.0.1:${port}/`);
  // Keep the server running for a while
  setTimeout(() => {
    console.log('Test server closing...');
    // Don't close so we can test connectivity
  }, 60000);
});

